# ==================== COLOR CODES FOR LOGS ====================
class ColorLog:
    """Color codes for log messages"""
    RED = '\033[91m'
    GREEN = '\033[92m'
    YELLOW = '\033[93m'
    BLUE = '\033[94m'
    MAGENTA = '\033[95m'
    CYAN = '\033[96m'
    WHITE = '\033[97m'
    BOLD = '\033[1m'
    RESET = '\033[0m'
    
    @staticmethod
    def colorize(text, color):
        return f"{color}{text}{ColorLog.RESET}"

