def safe_clear():
    """Clear console safely across platforms"""
    try:
        console.clear()
    except:
        os.system('clear' if sys.platform != 'win32' else 'cls')
        print("\n" * 2)

def authenticate():
    """Simple authentication with delay on failure"""
    console.print(Panel.fit("[bold cyan]CCT_DDOS LOGIN[/bold cyan]", border_style="cyan"))
    attempts = 0
    while attempts < 3:
        user = console.input("[cyan][?] Username: [white]").strip()
        pwd = console.input("[cyan][?] Password: [white]").strip()
        if user == USERNAME and pwd == PASSWORD:
            console.print("[green]✓ Authentication successful![/green]")
            time.sleep(1)
            return True
        else:
            attempts += 1
            console.print(f"[red]✗ Invalid credentials. {3-attempts} attempts left.[/red]")
            time.sleep(2)
    console.print("[red]Too many failed attempts. Exiting.[/red]")
    sys.exit(1)

# ==================== COLORED SLOWPRINT BANNER ====================
def slowprint_colored(text, color=ColorLog.CYAN, delay=0.008):
    """Print text slowly with color"""
    for ch in text:
        sys.stdout.write(f"{color}{ch}{ColorLog.RESET}")
        sys.stdout.flush()
        time.sleep(delay)
    sys.stdout.write("\n")

