# ==================== SOCIAL MEDIA REDIRECTS ====================
def open_android_link(url):
    try:
        subprocess.run(['am', 'start', '-a', 'android.intent.action.VIEW', '-d', url], capture_output=True, timeout=3)
        return True
    except:
        pass
    try:
        import webbrowser
        webbrowser.open(url)
        return True
    except:
        return False

def show_redirects():
    slowprint_colored(f"\n[+] Opening Facebook page...", ColorLog.CYAN)
    open_android_link("https://www.facebook.com/ChandpurCyberTeam")
    for i in range(5, 0, -1):
        sys.stdout.write(f"\r{ColorLog.CYAN}[+] Opening Telegram in {i} seconds...{ColorLog.RESET}")
        sys.stdout.flush()
        time.sleep(1)
    print()
    slowprint_colored(f"[+] Opening Telegram channel...", ColorLog.CYAN)
    open_android_link("https://t.me/Chandpur_Cyber_Team")
    time.sleep(1.5)
    slowprint_colored(f"[!] Press ENTER to continue to the main menu...", ColorLog.YELLOW)
    input()

# ==================== LOAD PROXIES ====================
def load_proxies():
    global proxies_list
    if os.path.exists("./proxy.txt"):
        with open("./proxy.txt", 'r') as f:
            proxies_list = [line.strip() for line in f if line.strip()]
        return len(proxies_list)
    return 0

def get_random_proxy():
    if proxies_list:
        proxy = random.choice(proxies_list)
        return {"http": f"http://{proxy}", "https": f"http://{proxy}"}
    return None

