def get_target(url):
    url = url.rstrip()
    target = {}
    target['uri'] = urlparse(url).path if urlparse(url).path else "/"
    target['host'] = urlparse(url).netloc
    target['scheme'] = urlparse(url).scheme
    target['port'] = urlparse(url).netloc.split(":")[1] if ":" in urlparse(url).netloc else ("443" if urlparse(url).scheme == "https" else "80")
    return target

