def attack_command_interface():
    safe_clear()
    console.print(Panel.fit("[bold red]ATTACK MODE[/bold red]", border_style="red"))
    console.print("[green]Type 'help' to see available methods, 'back' to return to main menu.[/green]")
    
    def local_command():
        cmd = console.input("[green]\n╔═══[CCT_ATTACK]\n╚══[cyan]> [/cyan]").strip().lower()
        if cmd == "back":
            return "back"
        elif cmd in ["cls", "clear"]:
            safe_clear()
            console.print(Panel.fit("[bold red]ATTACK MODE[/bold red]", border_style="red"))
            console.print("[green]Type 'help' to see available methods, 'back' to return to main menu.[/green]")
            return None
        elif cmd in ["help", "?"]:
            show_attack_help()
            return None
        elif cmd == "exit":
            sys.exit(0)
        else:
            process_attack_command(cmd)
            return None

    while True:
        res = local_command()
        if res == "back":
            break

